async function execute(browser, params) {
    const emailInput = await browser.extractComponent(
        {
            typeName: 'TextInput',
            schema: '{ title: string; cssSelector: string; placeholderText?: string; }'
        },
        'email newsletter signup'
    );
    if (!emailInput || !emailInput.cssSelector) {
        throw new Error('Could not find newsletter email input');
    }
    await browser.clearAndType(emailInput.cssSelector, params.emailAddress);
    const submitBtn = await browser.extractComponent(
        {
            typeName: 'Button',
            schema: '{ title: string; cssSelector: string; }'
        },
        'subscribe newsletter submit'
    );
    if (submitBtn && submitBtn.cssSelector) {
        await browser.click(submitBtn.cssSelector);
    } else {
        await browser.pressKey('Enter');
    }
    await browser.awaitPageInteraction();
    return { success: true, message: 'Signed up for newsletter with ' + params.emailAddress };
}
